--
-- Table structure for table `ai_training_dataset`
--

DROP TABLE IF EXISTS `ai_training_dataset`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `ai_training_dataset` (
  `training_dataset_id` bigint NOT NULL AUTO_INCREMENT COMMENT '학습 데이터셋 ID',
  `target_type` enum('EVENT','PROGRAM') NOT NULL COMMENT '예측 대상 유형',
  `event_id` bigint DEFAULT NULL COMMENT '행사 ID',
  `program_id` bigint DEFAULT NULL COMMENT '프로그램 ID',
  `base_timestamp` datetime NOT NULL COMMENT '입력 시퀀스 마지막 기준 시각',
  `input_sequence_json` json NOT NULL COMMENT '최근 60분 입력 시퀀스(JSON)',
  `target_avg_score_60m` decimal(10,2) NOT NULL COMMENT '다음 60분 평균 혼잡 점수',
  `target_peak_score_60m` decimal(10,2) NOT NULL COMMENT '다음 60분 최대 혼잡 점수',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '생성일시',
  PRIMARY KEY (`training_dataset_id`),
  UNIQUE KEY `uk_ai_training_target_base` (`target_type`,`event_id`,`program_id`,`base_timestamp`),
  KEY `ix_ai_training_target_type` (`target_type`),
  KEY `ix_ai_training_event_id` (`event_id`),
  KEY `ix_ai_training_program_id` (`program_id`),
  KEY `ix_ai_training_base_timestamp` (`base_timestamp`),
  CONSTRAINT `fk_ai_training_event` FOREIGN KEY (`event_id`) REFERENCES `event` (`event_id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `fk_ai_training_program` FOREIGN KEY (`program_id`) REFERENCES `event_program` (`program_id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `ck_ai_training_target_scores` CHECK (((`target_avg_score_60m` >= 0) and (`target_peak_score_60m` >= 0) and (`target_peak_score_60m` >= `target_avg_score_60m`)))
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='LSTM 학습용 입력/타깃 데이터셋';
/*!40101 SET character_set_client = @saved_cs_client */;

