--
-- Table structure for table `ai_prediction_logs`
--

DROP TABLE IF EXISTS `ai_prediction_logs`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `ai_prediction_logs` (
  `prediction_log_id` bigint NOT NULL AUTO_INCREMENT COMMENT '예측 로그 ID',
  `target_type` enum('EVENT','PROGRAM') NOT NULL COMMENT '예측 대상 유형',
  `event_id` bigint DEFAULT NULL COMMENT '행사 ID',
  `program_id` bigint DEFAULT NULL COMMENT '프로그램 ID',
  `prediction_base_time` datetime NOT NULL COMMENT '예측 기준 시각',
  `predicted_avg_score_60m` decimal(10,2) NOT NULL COMMENT '예측 평균 혼잡 점수',
  `predicted_peak_score_60m` decimal(10,2) NOT NULL COMMENT '예측 최대 혼잡 점수',
  `predicted_level` tinyint NOT NULL COMMENT '예측 혼잡도 레벨(1~5)',
  `model_version` varchar(50) NOT NULL DEFAULT 'v1' COMMENT '모델 버전',
  `source_type` enum('BATCH','REALTIME') NOT NULL DEFAULT 'REALTIME' COMMENT '예측 생성 방식',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '생성일시',
  PRIMARY KEY (`prediction_log_id`),
  KEY `ix_ai_prediction_target_event_time` (`target_type`,`event_id`,`created_at`),
  KEY `ix_ai_prediction_target_program_time` (`target_type`,`program_id`,`created_at`),
  KEY `ix_ai_prediction_base_time` (`prediction_base_time`),
  KEY `fk_ai_prediction_event` (`event_id`),
  KEY `fk_ai_prediction_program` (`program_id`),
  CONSTRAINT `fk_ai_prediction_event` FOREIGN KEY (`event_id`) REFERENCES `event` (`event_id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `fk_ai_prediction_program` FOREIGN KEY (`program_id`) REFERENCES `event_program` (`program_id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `ck_ai_prediction_scores` CHECK (((`predicted_avg_score_60m` >= 0) and (`predicted_peak_score_60m` >= 0) and (`predicted_peak_score_60m` >= `predicted_avg_score_60m`) and (`predicted_level` between 1 and 5)))
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='혼잡도 예측 결과 로그';
/*!40101 SET character_set_client = @saved_cs_client */;

